import{_ as l,o as a,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const o="/assets/image-20260219122501789.CMoKa4wG.png",c="/assets/image-20260219152009510.CdHmrORo.png",r="/assets/image-20260219145101986.CGxcGK4u.png",s="/assets/image-20260219145336078.DYPl3lWq.png",d="/assets/image-20260219160746095.sPZBdcnA.png",S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ES/Stm32/Stm32开发/项目组成.md","filePath":"ES/Stm32/Stm32开发/项目组成.md","lastUpdated":1775898880000}'),h={name:"ES/Stm32/Stm32开发/项目组成.md"};function m(p,e,n,_,x,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h3 id="设备家族包" tabindex="-1">设备家族包 <a class="header-anchor" href="#设备家族包" aria-label="Permalink to &quot;设备家族包&quot;">​</a></h3><p>设备家族包（Device Family Pack），用于让 IDE 识别并支持对应系列的芯片，Keil 构建 STM32 项目时需要导入对应芯片的设备家族包。</p><p>以 STM32F4 系列为例，截至目前其最新版本 DFP 为<code>Keil.STM32F4xx_DFP.3.1.1.pack</code>，其本质上是一个压缩包。里面包含了针对 STM32F4 系列芯片进行开发所需的各种核心文件：</p><ul><li>.pdsc 文件：一个 XML 格式的文件，但它有特定的扩展名是包描述文件，用于描述 DFP 的版本信息，文件结构，支持的芯片信息。</li><li>.svd 文件：System View Description (SVD) 是 XML 格式的系统视图描述文件，它包含了该芯片的所有外设、寄存器结构、地址映射以及详细的特性描述，用于在调试时告诉 IDE 外设寄存器信息。</li><li>.FLM 文件：烧录算法文件，是二进制文件，在烧录时用于初始化 Flash 控制器将用户程序写入 Flash。</li><li>.dbgconf 文件：调试配置文件，用于在调试时配置 MCU 的内部调试模块，可通过Keil 中的图像化界面更改配置。</li></ul><p>DFP 在版本 3.0.0（发布于2024年10月11日）进行了精简：</p><ul><li>删除了芯片参考手册。</li><li>删除了板级外设驱动和示例。</li><li>删除了HAL库 和 LL库驱动文件，较早版本的为标准库。</li><li>删除了使用于编译器的启动文件以及 CMSIS-Driver 相关文件。</li></ul><p>删除的大部分内容被移交到了 STM32CubeMX 固件包当中。</p><p>DFP 可通过 Keil 内部的 Pack Install 安装或更新，也可<a href="https://www.keil.arm.com/devices/" target="_blank" rel="noreferrer">在线下载</a>离线安装包。</p><p><img src="'+o+'" alt="image-20260219122501789"></p><h3 id="固件包" tabindex="-1">固件包 <a class="header-anchor" href="#固件包" aria-label="Permalink to &quot;固件包&quot;">​</a></h3><p>固件包（Firmware Package）用于配合 STM32CubeMX 生成工程模板。</p><p><img src="'+c+'" alt="image-20260219152009510"></p><p>上图中是固件包的主要组成部分：</p><ul><li>HAL 库（LL）驱动程序和一些评估板所需的 BSP 驱动。</li><li>CMSIS 组件相关的文件，包含启动文件，DSP库等。</li><li>中间层组件，包含有关RTOS，USB，UI等库。</li><li>官方评估开发板示例工程。</li></ul><p>固件包可通过 STM32CubeMX 获取：</p><p><img src="'+r+'" alt="image-20260219145101986"></p><p>安装后的固件包在如下路径可找到。<img src="'+s+'" alt="image-20260219145336078"></p><h3 id="外设驱动程序" tabindex="-1">外设驱动程序 <a class="header-anchor" href="#外设驱动程序" aria-label="Permalink to &quot;外设驱动程序&quot;">​</a></h3><p>STM32 单片机根据使用的外设驱动程序种类不同，通常有 HAL 库（LL库），标准库，寄存器三种开发方式。</p><ul><li>HAL 库又称为硬件抽象层（ Hardware Abstraction Layer），HAL 库将对 MCU 外设的操作封装成统一接口的函数，代码的可移植性好，但是由于层层封装导致性能开销较大，且开发者容易不熟悉硬件底层。</li><li>LL 库（Lower Layer）与 HAL 库捆绑发行，通过宏和内联函数的方式操作寄存器效率高，用于对性能要求极端的场景以解决 HAL库的弊端。</li><li>标准库的可移植性较差，意法半导体公司不再提供对标准库的支持，老项目常见使用。而寄存器的开发方式效率最高，但较为繁琐。</li></ul><p>在老版本的 DFP 中有标准库文件，也可在<a href="https://www.st.com.cn/zh/embedded-software/stm32-standard-peripheral-libraries.save-bookmark.html" target="_blank" rel="noreferrer">官网获取</a>。支持以下系列芯片。</p><p><img src="'+d+'" alt="image-20260219160746095"></p><p>HAL 库和LL 库可在固件包中获取，通常使用 STM32CubeMX 来完成外设初始化。</p><h3 id="文件说明" tabindex="-1">文件说明 <a class="header-anchor" href="#文件说明" aria-label="Permalink to &quot;文件说明&quot;">​</a></h3><p>以 STM32F103RCT6 的HAL库工程为例介绍以下文件的作用。</p><h4 id="startup-stm32f103xe-s" tabindex="-1">startup_stm32f103xe.s <a class="header-anchor" href="#startup-stm32f103xe-s" aria-label="Permalink to &quot;startup_stm32f103xe.s&quot;">​</a></h4><p>汇编文件，用于单片机启动时 C语言运行环境的搭建，详见 Stm32 启动过程。</p><h4 id="system-stm32f1xx-c-h" tabindex="-1">system_stm32f1xx.c/.h <a class="header-anchor" href="#system-stm32f1xx-c-h" aria-label="Permalink to &quot;system_stm32f1xx.c/.h&quot;">​</a></h4><p>这个文件用于配置系统时钟，其中编写了一个全局变量和两个函数：</p><ul><li><code>SystemCoreClock</code>： 存储当前系统内核时钟（HCLK）的频率值（单位为 Hz），用来设置 SysTick 计时器，作为系统时钟频率的唯一参考。</li><li><code>SystemInit()</code>：系统每次复位时默认使用 HSI 作为时钟源。这个函数在<code>startup_stm32f1xx_xx</code>中被调用，负责在主函数调用前来初始化系统的时钟（系统时钟源，PLL乘法器，AHB/APBx预分频器和Flash设置）。</li><li><code>SystemCoreClockUpdate()</code>：更新变量SystemCoreClock，必须在程序执行期间更改核心时钟时调用。</li></ul><p>头文件中包含了函数声明，在<code>stm32f103xe.h</code>文件中被引用。</p><h4 id="stm32f1xx-hal-c-h" tabindex="-1">stm32f1xx_hal.c/h <a class="header-anchor" href="#stm32f1xx-hal-c-h" aria-label="Permalink to &quot;stm32f1xx_hal.c/h&quot;">​</a></h4><ul><li>.c 文件中包含了HAL库一些公共函数的定义，这些函数实现了HAL库初始化（配置中断优先级分组；HAL库时钟初始化，1ms为时基），延时函数（依托 Systick 中断实现），获取设备ID，启动调试模块等功能。</li><li>.h 文件引用了<code>stm32fxxx_hal_conf.h</code>文件，包含了所有的HAL库函数的声明（大部分都在<code>stm32fxxx_hal_conf.h</code>引用的各个头文件中），定义了一些调试用的宏。</li></ul><h4 id="stm32f1xx-hal-conf-h" tabindex="-1">stm32f1xx_hal_conf.h <a class="header-anchor" href="#stm32f1xx-hal-conf-h" aria-label="Permalink to &quot;stm32f1xx_hal_conf.h&quot;">​</a></h4><p>这个文件用于裁剪配置HAL库。在 HAL库源码头文件目录下有一个配置文件的模板 <code>stm32f1xx_hal_conf_template.h</code> 。需要将这个文件拷贝更改为 <code>stm32f1xx_hal_conf.h </code>。在这个文件当中你可以通过修改宏定义来选择哪些外设的HAL库驱动头文件被包含在项目中，从而实现对HAL库的裁剪。</p><h4 id="stm32f103xe-h" tabindex="-1">stm32f103xe.h <a class="header-anchor" href="#stm32f103xe-h" aria-label="Permalink to &quot;stm32f103xe.h&quot;">​</a></h4><p>不同型号的芯片使用的该文件不同，这个文件主要包含以下内容：</p><ul><li>所有外设的数据结构和地址映射。</li><li>外设的寄存器声明和位定义。</li><li>访问外设寄存器硬件的宏。</li></ul><h4 id="stm32f1xx-h" tabindex="-1">stm32f1xx.h <a class="header-anchor" href="#stm32f1xx-h" aria-label="Permalink to &quot;stm32f1xx.h&quot;">​</a></h4><p>这个文件中包含了一些对寄存器位操作的宏定义（实现寄存器的原子化访问）并且引用了<code>stm32f1xx_hal.h</code>和<code>stm32f103xe.h</code>两个头文件。<code>main.c</code>中只需要引用这个头文件即可调用 HAL 库中的函数操作外设，也可直接操作寄存器。</p><ul><li>通过预处理器是否定义<code>USE_HAL_DRIVER</code>这个宏来决定是否引用<code>stm32f1xx_hal.h</code>，</li><li>通过定义芯片型号对应的宏来确定引用的对应的寄存器描述头文件，对于STM32F103RCT6 这个型号这里定义<code>STM32F103xE</code>这个宏引用<code>stm32f103xe.h</code>这个文件。</li></ul><h4 id="stm32f1xx-it-c" tabindex="-1">stm32f1xx_it.c <a class="header-anchor" href="#stm32f1xx-it-c" aria-label="Permalink to &quot;stm32f1xx_it.c&quot;">​</a></h4><p>这个文件中包含了一些异常处理中断服务函数，当运行发成异常时就会触发这些中断进而执行对应的中断服务函数，可以自行更改这些函数。同时用户编写的中断服务函数也可放在这里。</p><ul><li>NMI（非屏蔽中断）：通过 <code>NMI_Handler</code> 函数处理。</li><li>硬故障：当发生硬故障时，<code>HardFault_Handler</code> 会进入无限循环，通常用于调试。</li><li>内存管理异常：<code>MemManage_Handler</code> 也会进入无限循环。</li><li>总线故障：<code>BusFault_Handler</code> 处理总线故障并进入无限循环。</li><li>使用故障：<code>UsageFault_Handler</code> 处理使用故障并进入无限循环。</li><li>SVCall（Supervisor Call）、调试监视器和PendSV异常等。</li></ul><h4 id="core-cm3-h" tabindex="-1">core_cm3.h <a class="header-anchor" href="#core-cm3-h" aria-label="Permalink to &quot;core_cm3.h&quot;">​</a></h4><p>这个文件在<code>stm32f103xe.h</code>文件中被引用，是 Cortex-M3 内核的头文件，作用如下：</p><ol><li><p>定义内核寄存器：</p><ul><li><code>NVIC_Type</code>：嵌套向量中断控制器 (Nested Vectored Interrupt Controller)。</li><li><code>SysTick_Type</code>：系统滴答定时器 (System Tick Timer)。</li><li><code>SCB_Type</code>：系统控制块 (System Control Block)。</li><li><code>MPU_Type</code>：存储器保护单元 (Memory Protection Unit)。</li></ul></li><li><p>提供内核访问函数：</p><ul><li>执行复位 (<code>NVIC_SystemReset</code>)。</li><li>设置中断优先级 (<code>NVIC_SetPriority</code>)。</li><li>ITM 发送字符（<code>ITM_SendChar</code>）。</li></ul></li><li><p>标准化类型定义：定义了一些宏定义于规范寄存器访问。</p><ul><li><code>__I</code> (volatile const/只读)。</li><li><code>__O</code> (volatile/只写)。</li><li><code>__IO</code> (volatile/读写) 等宏。</li></ul></li></ol><h4 id="cmsis-compiler-h" tabindex="-1">cmsis_compiler.h <a class="header-anchor" href="#cmsis-compiler-h" aria-label="Permalink to &quot;cmsis_compiler.h&quot;">​</a></h4><p>这个文件在<code>core_cm3.h</code>中被引用，用于对不同编译器作兼容。<code>cmsis_compiler.h</code>文件会根据编译时产生的宏来判断编译器的种类，从而引用对应编译器头的适配文件。</p><ul><li><code>cmsis_armcc.h</code>：AC5编译器。</li><li><code>cmsis_armclang.h</code>：AC6编译器。</li><li><code>cmsis_gcc.h</code>：GUN GCC 编译器。</li><li><code>cmsis_irrarm.h</code>：IAR EWARM编译器。</li></ul><p>这些头文件通过宏定义的形式将 CMSIS 标准宏翻译成它们所适配编译器能看懂的语法。同时实现了Cortex-M 内核的一些特殊汇编指令。</p><p>这些文件的引用关系如下图所示：</p><p class="img-scale-75">![Hardware FIFO ID len Flow-2026-02-20-155039](./Picture/Hardware FIFO ID len Flow-2026-02-20-155039.png)</p><h3 id="工程模板" tabindex="-1">工程模板 <a class="header-anchor" href="#工程模板" aria-label="Permalink to &quot;工程模板&quot;">​</a></h3><p>工程模板可以参考使用：</p><ol><li><a href="https://github.com/XJU-Hurricane-Team/STM32-Template" target="_blank" rel="noreferrer">Hurricane-STM32-Template</a></li><li><a href="https://github.com/Deadline039/STM32-Template" target="_blank" rel="noreferrer">Deadline039的工程模板</a>。</li><li>STM32CubeMX 生成的工程。</li><li>正点原子的工程。</li></ol>',56)])])}const b=l(h,[["render",m]]);export{S as __pageData,b as default};
